import React, { useState, useEffect, useRef } from 'react';
import './matrix.css';
import Handler from '../api/Data';

const Matrix = () => {
  const [rows, setRows] = useState(5);
  const [columns, setColumns] = useState(5);
  const [grid, setGrid] = useState([]);
  const [sizeplayer, setSize] = useState(0);

  // data grid
  const [data, setData] = useState(null);
  // reference
  const matrixRef = useRef([]);
  // winner checker
  const [ifwin, setIfwin] = useState(0);

  useEffect(() => {
    let newGrid = [];
    for (let i = 0; i < rows; i++) {
      let row = [];
      for (let j = 0; j < columns; j++) {
        row.push(0);
      }
      newGrid.push(row);
    }
    setGrid(newGrid);
  }, [rows, columns]);

  useEffect(() => {
    async function fetchData() {
      const response = await fetch("http://localhost:5000/grid");
      const jsonData = await response.json();
      setData(jsonData);
    }

    fetchData();
  }, []);

  const handleBoxClick = (row, col) => {
    let newGrid = [...grid];
    newGrid[row][col] = newGrid[row][col] === 0 ? 1 : 0;
    setGrid(newGrid);
  };

  const renderMatrix = () => {
    let matrix = [];
    for (let i = 0; i < rows; i++) {
      let row = [];
      for (let j = 0; j < columns; j++) {
        if (grid[i] && grid[i][j] !== undefined) {
          row.push(
            <div
              className="grid-square"
              style={{ backgroundColor: grid[i][j] === 0 ? "white" : "black" }}
              onClick={() => handleBoxClick(i, j)}
              key={`${i}-${j}`}
              ref={el => (matrixRef.current[i * columns + j] = el)}
            />
          );
        }
      }
      matrix.push(
        <div className="grid-row" style={{ display: 'flex', flexDirection: 'column' }} key={i}>
          {row}
        </div>
      );
    }
    return matrix;
  };

  useEffect(() => {
    const checkGrid = () => {
      let index = 0;
      for (let i = 0; i < rows; i++) {
        for (let j = 0; j < columns; j++) {
          const matrixValue = matrixRef.current[index].style.backgroundColor === "black" ? 1 : 0;
          if (data[i][j] !== matrixValue) {
            console.log("Grid has changed!");
            setData(getDataFromMatrix(matrixRef.current));
            return;
            }
            index++;
            }
            }
        };

        const intervalId = setInterval(checkGrid, 1000);

        return () => clearInterval(intervalId);

    }, [rows, columns]);

    return (
    <div className="game">
    <div className="grid" ref={matrixRef}>
    {renderMatrix(rows, columns)}
    </div>
    </div>
    );
}

export default Matrix;
